import React, { useRef, useState } from 'react';
import GanttBar from './GanttBar';
import EventBar from './EventBar';

const LEFT_WIDTH   = 260;
const DAY_WIDTH    = 38;
const GROUP_HEIGHT = 32;
const SUB_HEIGHT   = 40;
const ITEM_HEIGHT  = 40;
const HEADER_HEIGHT = 56;
const BAR_PADDING  = 5;

const MONTH_NAMES = ['January','February','March','April','May','June','July','August','September','October','November','December'];

const SQUAD_COLORS = [
  { bg: '#E3FCEF', border: '#00875A', text: '#006644' },
  { bg: '#DEEBFF', border: '#0052CC', text: '#0747A6' },
  { bg: '#EAE6FF', border: '#5243AA', text: '#403294' },
  { bg: '#FFEBE6', border: '#BF2600', text: '#BF2600' },
  { bg: '#FFF0B3', border: '#FF8B00', text: '#FF8B00' },
  { bg: '#E6FCFF', border: '#00B8D9', text: '#006887' },
  { bg: '#FFEDF5', border: '#CD519D', text: '#943D73' },
];

function getSquadColor(name) {
  let h = 0;
  for (let i = 0; i < name.length; i++) h = (h * 31 + name.charCodeAt(i)) & 0xffffffff;
  return SQUAD_COLORS[Math.abs(h) % SQUAD_COLORS.length];
}

function parseDate(str) {
  if (!str) return null;
  const [y, m, d] = str.split('-').map(Number);
  return new Date(y, m - 1, d);
}

function addDays(date, n) {
  const d = new Date(date); d.setDate(d.getDate() + n); return d;
}

function daysBetween(a, b) { return Math.round((b - a) / 86400000); }

function fmtISODate(d) {
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
}

function fmtDateShort(d) {
  return `${['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][d.getMonth()]} ${d.getDate()}`;
}

function getFieldValue(fields, key) {
  const v = fields?.[key];
  if (v == null) return 'None';
  if (typeof v === 'string') return v || 'None';
  if (typeof v === 'number') return String(v);
  if (Array.isArray(v)) {
    if (!v.length) return 'None';
    const f = v[0];
    return typeof f === 'string' ? f : (f?.displayName || f?.name || f?.value || 'None');
  }
  return v.displayName || v.name || v.value || v.key || '—';
}

function getItemDates(item, sdf, edf) {
  if (item._type === 'custom') {
    let s = parseDate(item.startDate), e = parseDate(item.endDate);
    if (!s && !e) { const r = new Date(); s = r; e = addDays(r, 1); }
    if (!s) s = e; if (!e) e = addDays(s, 1);
    return { s, e };
  }
  let s = parseDate(item.fields[sdf]);
  let e = parseDate(item.fields[edf]);
  if (!s && !e) { const r = new Date(); s = addDays(r, -3); e = addDays(r, 3); }
  if (!s) s = addDays(e, -7);
  if (!e) e = addDays(s, 7);
  return { s, e };
}

function computeRollup(items, sdf, edf) {
  let minS = null, maxE = null;
  for (const item of items) {
    const { s, e } = getItemDates(item, sdf, edf);
    if (!minS || s < minS) minS = s;
    if (!maxE || e > maxE) maxE = e;
  }
  return { s: minS, e: maxE };
}

function groupItems(issues, events, f1, f2) {
  const g = {};
  for (const iss of issues) {
    const g1 = getFieldValue(iss.fields, f1) || 'None';
    const g2 = getFieldValue(iss.fields, f2) || 'None';
    if (!g[g1]) g[g1] = {};
    if (!g[g1][g2]) g[g1][g2] = [];
    g[g1][g2].push({ ...iss, _type: 'jira' });
  }
  for (const evt of (events || [])) {
    const g1 = evt.groupValues?.[f1] ?? evt.squad ?? 'No Squad';
    const g2 = evt.groupValues?.[f2] ?? evt.developer ?? 'Unassigned';
    if (!g[g1]) g[g1] = {};
    if (!g[g1][g2]) g[g1][g2] = [];
    g[g1][g2].push({ ...evt, _type: 'custom' });
  }
  return g;
}

function RollupBar({ s, e, viewStart, totalDays, color, height, rowH }) {
  if (!s || !e) return null;
  const left  = Math.max(0, daysBetween(viewStart, s)) * DAY_WIDTH;
  const right = Math.min(totalDays, daysBetween(viewStart, e) + 1) * DAY_WIDTH;
  if (right <= left) return null;
  return (
    <div style={{
      position: 'absolute', left, width: right - left,
      height: height || 8, top: '50%', transform: 'translateY(-50%)',
      background: color.border, borderRadius: 4, opacity: 0.3,
      pointerEvents: 'none', zIndex: 1,
    }} />
  );
}

function CreatePreview({ startDay, endDay, color, rowH }) {
  const lo = Math.min(startDay, endDay), hi = Math.max(startDay, endDay);
  const w = Math.max((hi - lo + 1) * DAY_WIDTH, DAY_WIDTH * 2);
  return (
    <div style={{
      position: 'absolute', left: lo * DAY_WIDTH, top: 4,
      width: w, height: rowH - 8,
      background: color.bg, border: `2px dashed ${color.border}`,
      borderRadius: 6, opacity: 0.85, zIndex: 8, pointerEvents: 'none',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
    }}>
      <span style={{ fontSize: '10px', color: color.text, fontWeight: 700 }}>+ New event</span>
    </div>
  );
}

export default function GanttChart({
  issues, customEvents, viewYear, viewMonth, numMonths,
  groupByField1, groupByField2, groupByField1Label, groupByField2Label,
  startDateField, endDateField, today,
  onEditEvent, onDeleteEvent, onUpdateEvent, onUpdateIssue, onCreateEvent,
}) {
  const scrollRef = useRef(null);
  const [collapsedGroups, setCollapsedGroups] = useState(new Set());
  const [collapsedSubs, setCollapsedSubs]     = useState(new Set());
  const [createDrag, setCreateDrag]           = useState(null);

  const nm  = Math.max(1, numMonths || 1);
  const sdf = startDateField || 'customfield_10015';
  const edf = endDateField   || 'duedate';
  const f1  = groupByField1  || 'labels';
  const f2  = groupByField2  || 'assignee';

  const viewStart  = new Date(viewYear, viewMonth, 1);
  const viewEnd    = new Date(viewYear, viewMonth + nm, 0);
  const totalDays  = daysBetween(viewStart, viewEnd) + 1;
  const totalWidth = totalDays * DAY_WIDTH;
  const todayOff   = daysBetween(viewStart, today) * DAY_WIDTH;

  const grouped    = groupItems(issues, customEvents || [], f1, f2);
  const groupNames = Object.keys(grouped).sort();

  // Build flat row list
  const rows = [];
  for (const g1 of groupNames) {
    const color   = getSquadColor(g1);
    const allItems = Object.values(grouped[g1]).flat();
    const rollup  = computeRollup(allItems, sdf, edf);
    rows.push({ type: 'group', g1, color, rollup, count: allItems.length });

    if (!collapsedGroups.has(g1)) {
      const subNames = Object.keys(grouped[g1]).sort();
      for (const g2 of subNames) {
        const items   = grouped[g1][g2];
        const subKey  = `${g1}||${g2}`;
        const subRoll = computeRollup(items, sdf, edf);
        rows.push({ type: 'sub', g1, g2, color, rollup: subRoll, count: items.length, subKey });
        if (!collapsedSubs.has(subKey)) {
          for (const item of items) {
            rows.push({ type: 'item', g1, g2, color, item, subKey });
          }
        }
      }
    }
  }

  function toggleGroup(g1) {
    setCollapsedGroups(prev => { const n = new Set(prev); n.has(g1) ? n.delete(g1) : n.add(g1); return n; });
  }
  function toggleSub(key) {
    setCollapsedSubs(prev => { const n = new Set(prev); n.has(key) ? n.delete(key) : n.add(key); return n; });
  }

  // Click-to-create drag
  function getDay(clientX) {
    const rect = scrollRef.current.getBoundingClientRect();
    const x    = clientX - rect.left - LEFT_WIDTH + scrollRef.current.scrollLeft;
    return Math.max(0, Math.min(totalDays - 1, Math.floor(x / DAY_WIDTH)));
  }

  function handleBgMouseDown(e, g1, g2) {
    if (e.button !== 0) return;
    e.preventDefault();
    const startDay = getDay(e.clientX);
    setCreateDrag({ g1, g2, startDay, curDay: startDay });

    const onMove = (ev) => setCreateDrag(p => p ? { ...p, curDay: getDay(ev.clientX) } : null);
    const onUp   = (ev) => {
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
      const endDay = getDay(ev.clientX);
      const lo = Math.min(startDay, endDay), hi = Math.max(startDay, endDay);
      setCreateDrag(null);
      if (onCreateEvent) {
        onCreateEvent({
          startDate: fmtISODate(addDays(viewStart, lo)),
          endDate:   fmtISODate(addDays(viewStart, hi)),
          g1, g2,
        });
      }
    };
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup',   onUp);
  }

  // ── Header ────────────────────────────────────────────────────────────────
  function renderHeader() {
    const dayEls  = [];
    const topEls  = [];

    if (nm > 1) {
      // Top row: month labels
      let mStart = 0, mLabel = '', mMo = -1;
      for (let i = 0; i <= totalDays; i++) {
        const d  = i < totalDays ? addDays(viewStart, i) : null;
        const mo = d ? d.getMonth() : -1;
        if (mo !== mMo) {
          if (mMo !== -1) {
            topEls.push(
              <div key={`m-${mStart}`} style={{ ...styles.weekLabel, left: mStart * DAY_WIDTH, width: (i - mStart) * DAY_WIDTH, fontWeight: 700, fontSize: '11px', color: '#172B4D' }}>
                {mLabel}
              </div>
            );
          }
          mMo = mo; mStart = i; mLabel = d ? `${MONTH_NAMES[d.getMonth()]} ${d.getFullYear()}` : '';
        }
      }
    } else {
      // Top row: week labels
      let wStart = 0, wLabel = '';
      for (let i = 0; i <= totalDays; i++) {
        const d = i < totalDays ? addDays(viewStart, i) : null;
        if (!d || d.getDay() === 0 || i === 0) {
          if (i > 0) topEls.push(
            <div key={`w-${wStart}`} style={{ ...styles.weekLabel, left: wStart * DAY_WIDTH, width: (i - wStart) * DAY_WIDTH }}>{wLabel}</div>
          );
          if (d) { wStart = i; wLabel = fmtDateShort(d); }
        }
      }
      topEls.push(
        <div key={`w-last`} style={{ ...styles.weekLabel, left: wStart * DAY_WIDTH, width: (totalDays - wStart) * DAY_WIDTH }}>{wLabel}</div>
      );
    }

    for (let i = 0; i < totalDays; i++) {
      const d = addDays(viewStart, i);
      const isToday   = daysBetween(today, d) === 0;
      const isWeekend = d.getDay() === 0 || d.getDay() === 6;
      dayEls.push(
        <div key={i} style={{
          ...styles.dayCell, left: i * DAY_WIDTH,
          background: isToday ? '#DEEBFF' : isWeekend ? '#F4F5F7' : '#fff',
          fontWeight: isToday ? 700 : 400,
          color:      isToday ? '#0052CC' : isWeekend ? '#97A0AF' : '#42526E',
        }}>
          <div style={styles.dayName}>{['Su','Mo','Tu','We','Th','Fr','Sa'][d.getDay()]}</div>
          <div style={styles.dayNum}>{d.getDate()}</div>
        </div>
      );
    }

    return (
      <div style={{ position: 'relative', height: HEADER_HEIGHT, width: totalWidth }}>
        <div style={{ position: 'relative', height: 22 }}>{topEls}</div>
        <div style={{ position: 'relative', height: 34 }}>{dayEls}</div>
      </div>
    );
  }

  function renderWeekendShading(rowH) {
    return Array.from({ length: totalDays }, (_, i) => {
      const d = addDays(viewStart, i);
      if (d.getDay() !== 0 && d.getDay() !== 6) return null;
      return <div key={i} style={{ position: 'absolute', left: i * DAY_WIDTH, top: 0, width: DAY_WIDTH, height: rowH, background: '#F4F5F7', pointerEvents: 'none' }} />;
    });
  }

  const totalItems = issues.length + (customEvents || []).length;
  if (totalItems === 0) {
    return (
      <div style={styles.emptyState}>
        <div style={{ fontSize: '48px' }}>📋</div>
        <div style={{ fontWeight: 600, fontSize: '16px', color: '#172B4D' }}>No issues found</div>
        <div style={{ color: '#6B778C', fontSize: '13px' }}>Configure a JQL filter or select projects in ⚙ Configure.</div>
      </div>
    );
  }

  const headerLabel = `${(groupByField1Label || f1).toUpperCase()} / ${(groupByField2Label || f2).toUpperCase()}`;

  return (
    <div style={styles.outer}>
      {/* Left header */}
      <div style={styles.leftHeader}>
        <span style={{ fontWeight: 600, fontSize: '11px', color: '#6B778C', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{headerLabel}</span>
        <span style={{ fontSize: '11px', color: '#97A0AF', flexShrink: 0, marginLeft: '6px' }}>
          {issues.length} issue{issues.length !== 1 ? 's' : ''}
          {(customEvents || []).length > 0 ? ` · ${customEvents.length} event${customEvents.length !== 1 ? 's' : ''}` : ''}
        </span>
      </div>

      {/* Timeline header */}
      <div style={{ position: 'absolute', left: LEFT_WIDTH, top: 0, right: 0, height: HEADER_HEIGHT, overflowX: 'hidden', background: '#fff', borderBottom: '2px solid #DFE1E6', zIndex: 10 }} id="gantt-header-scroll">
        {renderHeader()}
      </div>

      {/* Body */}
      <div
        id="gantt-body-scroll"
        ref={scrollRef}
        style={{ position: 'absolute', left: 0, top: HEADER_HEIGHT, right: 0, bottom: 0, overflowY: 'auto', overflowX: 'auto' }}
        onScroll={(e) => { const h = document.getElementById('gantt-header-scroll'); if (h) h.scrollLeft = e.currentTarget.scrollLeft; }}
      >
        <div style={{ display: 'flex', minWidth: LEFT_WIDTH + totalWidth }}>

          {/* Sticky left column */}
          <div style={{ width: LEFT_WIDTH, flexShrink: 0, position: 'sticky', left: 0, zIndex: 5, background: '#fff', borderRight: '2px solid #DFE1E6' }}>
            {rows.map((row, idx) => {
              if (row.type === 'group') {
                const col = row.color;
                return (
                  <div key={`lG-${row.g1}`}
                    style={{ height: GROUP_HEIGHT, display: 'flex', alignItems: 'center', gap: '6px', padding: '0 8px', background: col.bg, borderLeft: `4px solid ${col.border}`, color: col.text, cursor: 'pointer', borderBottom: `1px solid ${col.border}22`, userSelect: 'none', overflow: 'hidden' }}
                    onClick={() => toggleGroup(row.g1)}
                  >
                    <span style={{ fontSize: '9px', flexShrink: 0 }}>{collapsedGroups.has(row.g1) ? '▶' : '▼'}</span>
                    <span style={{ fontWeight: 700, fontSize: '12px', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{row.g1}</span>
                    <span style={{ fontSize: '11px', opacity: 0.6, flexShrink: 0 }}>{row.count}</span>
                  </div>
                );
              }
              if (row.type === 'sub') {
                const col = row.color;
                const isCol = collapsedSubs.has(row.subKey);
                return (
                  <div key={`lS-${row.g1}-${row.g2}`}
                    style={{ height: SUB_HEIGHT, display: 'flex', alignItems: 'center', gap: '6px', padding: '0 8px 0 16px', background: '#FAFBFC', borderLeft: `3px solid ${col.border}88`, borderBottom: '1px solid #F0F0F0', cursor: 'pointer', userSelect: 'none', overflow: 'hidden' }}
                    onClick={() => toggleSub(row.subKey)}
                  >
                    <span style={{ fontSize: '9px', color: '#6B778C', flexShrink: 0 }}>{isCol ? '▶' : '▼'}</span>
                    <div style={{ width: 24, height: 24, borderRadius: '50%', background: col.bg, border: `1px solid ${col.border}`, color: col.text, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '9px', fontWeight: 700, flexShrink: 0 }}>
                      {row.g2.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase()}
                    </div>
                    <span style={{ fontSize: '12px', fontWeight: 600, flex: 1, color: '#172B4D', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{row.g2}</span>
                    <span style={{ fontSize: '11px', color: '#97A0AF', flexShrink: 0 }}>{row.count}</span>
                  </div>
                );
              }
              // item row
              const item = row.item;
              const col  = row.color;
              const label = item._type === 'jira'
                ? <><span style={{ background: col.bg, color: col.text, border: `1px solid ${col.border}`, borderRadius: '3px', padding: '1px 5px', fontSize: '10px', fontWeight: 700, flexShrink: 0, marginRight: 4 }}>{item.key}</span><span style={{ fontSize: '11px', color: '#172B4D', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{item.fields.summary}</span></>
                : <span style={{ fontSize: '11px', color: '#172B4D', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{item.title || item.type}</span>;
              return (
                <div key={`lI-${row.g1}-${row.g2}-${item._type === 'jira' ? item.key : item.id}`}
                  style={{ height: ITEM_HEIGHT, display: 'flex', alignItems: 'center', gap: 0, padding: '0 8px 0 28px', background: idx % 2 === 0 ? '#fff' : '#FAFBFC', borderLeft: `2px solid ${col.border}44`, borderBottom: '1px solid #F4F5F7', overflow: 'hidden' }}
                >
                  {label}
                </div>
              );
            })}
          </div>

          {/* Timeline body */}
          <div style={{ width: totalWidth, flexShrink: 0 }}>
            {rows.map((row, idx) => {
              if (row.type === 'group') {
                return (
                  <div key={`rG-${row.g1}`} style={{ position: 'relative', height: GROUP_HEIGHT, background: row.color.bg, borderBottom: `1px solid ${row.color.border}22`, opacity: 0.7 }}>
                    {renderWeekendShading(GROUP_HEIGHT)}
                    {todayOff >= 0 && todayOff <= totalWidth && <div style={{ ...styles.todayLine, left: todayOff }} />}
                    <RollupBar s={row.rollup.s} e={row.rollup.e} viewStart={viewStart} totalDays={totalDays} color={row.color} height={10} />
                  </div>
                );
              }
              if (row.type === 'sub') {
                return (
                  <div key={`rS-${row.g1}-${row.g2}`} style={{ position: 'relative', height: SUB_HEIGHT, background: '#FAFBFC', borderBottom: '1px solid #EBEBEB' }}
                    onMouseDown={(e) => handleBgMouseDown(e, row.g1, row.g2)}
                  >
                    {renderWeekendShading(SUB_HEIGHT)}
                    {todayOff >= 0 && todayOff <= totalWidth && <div style={{ ...styles.todayLine, left: todayOff }} />}
                    <RollupBar s={row.rollup.s} e={row.rollup.e} viewStart={viewStart} totalDays={totalDays} color={row.color} height={8} />
                    {createDrag?.g1 === row.g1 && createDrag?.g2 === row.g2 && (
                      <CreatePreview startDay={createDrag.startDay} endDay={createDrag.curDay} color={row.color} rowH={SUB_HEIGHT} />
                    )}
                  </div>
                );
              }
              // item row
              const item = row.item;
              const bg   = idx % 2 === 0 ? '#fff' : '#FAFBFC';
              return (
                <div key={`rI-${row.g1}-${row.g2}-${item._type === 'jira' ? item.key : item.id}`}
                  style={{ position: 'relative', height: ITEM_HEIGHT, background: bg, borderBottom: '1px solid #F4F5F7' }}
                >
                  {/* Background — click-to-create */}
                  <div style={{ position: 'absolute', inset: 0, zIndex: 0, cursor: 'crosshair' }}
                    onMouseDown={(e) => handleBgMouseDown(e, row.g1, row.g2)}
                  />
                  {renderWeekendShading(ITEM_HEIGHT)}
                  {todayOff >= 0 && todayOff <= totalWidth && <div style={{ ...styles.todayLine, left: todayOff }} />}
                  {item._type === 'custom'
                    ? <EventBar key={item.id} event={item} viewStart={viewStart} dayWidth={DAY_WIDTH} rowHeight={ITEM_HEIGHT} barPadding={BAR_PADDING} totalDays={totalDays} onEdit={onEditEvent} onDelete={onDeleteEvent} onUpdate={onUpdateEvent} />
                    : <GanttBar key={item.key} issue={item} viewStart={viewStart} dayWidth={DAY_WIDTH} rowHeight={ITEM_HEIGHT} barPadding={BAR_PADDING} totalDays={totalDays} squadColor={row.color} onUpdate={onUpdateIssue} startDateField={sdf} endDateField={edf} />
                  }
                  {createDrag?.g1 === row.g1 && createDrag?.g2 === row.g2 && (
                    <CreatePreview startDay={createDrag.startDay} endDay={createDrag.curDay} color={row.color} rowH={ITEM_HEIGHT} />
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  outer:      { position: 'relative', flex: 1, overflow: 'hidden', background: '#fff' },
  leftHeader: {
    position: 'absolute', left: 0, top: 0, width: LEFT_WIDTH, height: HEADER_HEIGHT,
    background: '#fff', borderRight: '2px solid #DFE1E6', borderBottom: '2px solid #DFE1E6',
    zIndex: 11, display: 'flex', alignItems: 'center', padding: '0 12px',
  },
  weekLabel: {
    position: 'absolute', top: 0, height: 22, display: 'flex', alignItems: 'center',
    paddingLeft: '6px', fontSize: '10px', fontWeight: 600, color: '#6B778C',
    textTransform: 'uppercase', letterSpacing: '0.5px', borderRight: '1px solid #EBECF0', boxSizing: 'border-box',
  },
  dayCell: {
    position: 'absolute', top: 0, width: DAY_WIDTH, height: 34,
    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
    borderRight: '1px solid #EBECF0', boxSizing: 'border-box',
  },
  dayName:    { fontSize: '10px', opacity: 0.7 },
  dayNum:     { fontWeight: 600, fontSize: '12px' },
  todayLine:  { position: 'absolute', top: 0, bottom: 0, width: 2, background: '#0052CC', zIndex: 4, pointerEvents: 'none' },
  emptyState: { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '12px', color: '#6B778C' },
};
